def func(a, b=None ,c=None ,d=None):
    ret = a
    if b is not None:
        ret *= b
    if c is not None:
        ret *= c
    if d is not None:
        ret *= d
    return ret

a,b,c,d = map(float,input().split(','))
print(f"""前两个数乘积为：{func(a,b):.01f}
前三个数乘积为：{func(a,b,c):.01f}
前四个数乘积为：{func(a,b,c,d):.01f}""")
